using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval — returns JsonTypeInfo<Person> directly.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata : {personInfo.Type.Name}  (kind: {personInfo.Kind})");

// Round-trip via the metadata to prove it works.
string json = JsonSerializer.Serialize(new Person("Ada", 37), personInfo);
Person p = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Round-tripped       : {p}");

// 2) Probe without throwing — TryGetTypeInfo returns false when metadata
//    isn't available instead of throwing InvalidOperationException.
//    Use a resolver that only knows about int, so Person is "missing".
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new LimitedResolver()
};

if (limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"Found metadata      : {found!.Type.Name}");
else
    Console.WriteLine("No metadata for Person — and no exception thrown.");

if (limited.TryGetTypeInfo(typeof(int), out JsonTypeInfo? intInfo))
    Console.WriteLine($"Found metadata      : {intInfo!.Type.Name}");
else
    Console.WriteLine("No metadata for int.");

// --- types ---------------------------------------------------------------
record Person(string Name, int Age);

/// A resolver that only handles System.Int32 and returns null for everything else.
sealed class LimitedResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(int))
            return JsonMetadataServices.CreateValueInfo<int>(options, JsonMetadataServices.Int32Converter);

        return null;  // "not supported"
    }
}

